<?php declare(strict_types=1);
namespace App\Services;
final class VideoMetadataService { public function inspect(string $file):array{$probe=config('ffmpeg.ffprobe_path');$command=escapeshellarg($probe).' -v error -show_entries stream=codec_type,codec_name,width,height,r_frame_rate,bit_rate -of json '.escapeshellarg($file);$raw=shell_exec($command);$data=json_decode((string)$raw,true)?:[];$video=[];$audio=false;foreach($data['streams']??[] as $stream){if(($stream['codec_type']??'')==='video')$video=$stream;if(($stream['codec_type']??'')==='audio')$audio=true;}if(!$video)throw new \RuntimeException('Video metadata could not be detected.');[$n,$d]=array_pad(explode('/',$video['r_frame_rate']??'0/1',2),2,1);return ['width'=>(int)$video['width'],'height'=>(int)$video['height'],'fps'=>(float)$n/max(1,(float)$d),'codec'=>$video['codec_name']??'unknown','bitrate'=>(int)($video['bit_rate']??0),'has_audio'=>$audio];} }
